namespace sv_fa5fff4437e14deaa6cae8617b168d4c.Client.Models;

public sealed record StatusUpdate(DateTime Timestamp, string Status, string Location);

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTime EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

using sv_fa5fff4437e14deaa6cae8617b168d4c.Client.Models;

namespace sv_fa5fff4437e14deaa6cae8617b168d4c.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_fa5fff4437e14deaa6cae8617b168d4c.Client.Models;

namespace sv_fa5fff4437e14deaa6cae8617b168d4c.Client.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            new DateTime(2026, 6, 2, 17, 0, 0, DateTimeKind.Utc),
            [
                new StatusUpdate(new DateTime(2026, 5, 24, 8, 0, 0, DateTimeKind.Utc), "Picked Up", "New York, NY"),
                new StatusUpdate(new DateTime(2026, 5, 25, 14, 30, 0, DateTimeKind.Utc), "In Transit", "Philadelphia, PA"),
                new StatusUpdate(new DateTime(2026, 5, 26, 10, 15, 0, DateTimeKind.Utc), "In Transit", "Chicago, IL"),
            ]),

        ["TRK-002"] = new Shipment(
            "TRK-002",
            "Delivered",
            "San Francisco, CA",
            new DateTime(2026, 5, 25, 12, 0, 0, DateTimeKind.Utc),
            [
                new StatusUpdate(new DateTime(2026, 5, 22, 9, 0, 0, DateTimeKind.Utc), "Picked Up", "Seattle, WA"),
                new StatusUpdate(new DateTime(2026, 5, 23, 16, 0, 0, DateTimeKind.Utc), "In Transit", "Portland, OR"),
                new StatusUpdate(new DateTime(2026, 5, 24, 11, 45, 0, DateTimeKind.Utc), "Out for Delivery", "San Francisco, CA"),
                new StatusUpdate(new DateTime(2026, 5, 24, 15, 20, 0, DateTimeKind.Utc), "Delivered", "San Francisco, CA"),
            ]),

        ["TRK-003"] = new Shipment(
            "TRK-003",
            "Processing",
            "Dallas, TX",
            new DateTime(2026, 6, 5, 18, 0, 0, DateTimeKind.Utc),
            [
                new StatusUpdate(new DateTime(2026, 5, 27, 7, 0, 0, DateTimeKind.Utc), "Order Placed", "Dallas, TX"),
            ]),
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_fa5fff4437e14deaa6cae8617b168d4c.Client.Models
@using sv_fa5fff4437e14deaa6cae8617b168d4c.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

<h2>Shipment Tracker</h2>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <p><strong>Loading shipment details for @TrackingNumber…</strong></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="card mb-3">
        <div class="card-body">
            <h4 class="card-title">@_shipment.TrackingNumber</h4>
            <p><strong>Status:</strong> @_shipment.Status</p>
            <p><strong>Location:</strong> @_shipment.Location</p>
            <p><strong>Estimated Delivery:</strong> @_shipment.EstimatedDelivery.ToString("f")</p>
        </div>
    </div>

    <h5>Status History</h5>
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Time</th>
                <th>Status</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.StatusUpdates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Status</td>
                    <td>@update.Location</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently stop.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

